mapper.select:
SELECT eim.UTLINSTT_ID , eim.ETNM AS BPLC_NM
, tbivcl.INVM_CMP_PTRN_CD , ccd.COM_CD_NM AS INVM_CMP_PTRN_NM , nid.ENPR_INRD_CON , cfl.CNRN_TAGS
, CASE WHEN TRIM(eim.CMPNY_LOGO_IMAGE_FILE) IS NULL THEN eim.CMPNY_LOGO_BASS_IMAGE_FILE ELSE eim.CMPNY_LOGO_IMAGE_FILE END AS LOGO_IMAGE_URL
, CASE WHEN TRIM(eim.CMPNY_LOGO_IMAGE_FILE) IS NULL THEN 'Y' ELSE 'N' END AS DEFAULT_LOGO_YN FROM TB_BOX_IVT_ENPR_INFO_M eim LEFT JOIN TB_BOX_IVT_VNCM_CPTL_L tbivcl ON eim.UTLINSTT_ID = tbivcl.UTLINSTT_ID LEFT JOIN TB_BOX_IVT_COM_CD_D ccd ON ccd.COM_CD_ID = tbivcl.INVM_CMP_PTRN_CD LEFT JOIN TB_BOX_IVT_ENPR_INFO_D nid ON eim.UTLINSTT_ID = nid.UTLINSTT_ID LEFT JOIN ( SELECT UTLINSTT_ID
, AGGR_CONCAT(CNRN_FILD_NM, ',') AS CNRN_TAGS FROM TB_BOX_IVT_CNRN_FILD_L GROUP BY UTLINSTT_ID ) cfl ON eim.UTLINSTT_ID = cfl.UTLINSTT_ID
INNER JOIN ( SELECT UTLINSTT_ID FROM TB_BOX_IVT_ENPR_IVFL_R WHERE INVM_FILD_CD IN (
#{item}
) GROUP BY UTLINSTT_ID ) eir ON eim.UTLINSTT_ID = eir.UTLINSTT_ID
INNER JOIN ( SELECT UTLINSTT_ID FROM TB_BOX_IVT_ENPR_TCHN_R WHERE UTLZ_TCHN_CD IN (
#{item}
) GROUP BY UTLINSTT_ID ) etr ON eim.UTLINSTT_ID = etr.UTLINSTT_ID
INNER JOIN ( SELECT UTLINSTT_ID FROM TB_BOX_IVT_INVM_STG_R WHERE INVM_STG_CD IN (
#{item}
) GROUP BY UTLINSTT_ID ) isr ON eim.UTLINSTT_ID = isr.UTLINSTT_ID
INNER JOIN ( SELECT UTLINSTT_ID FROM TB_BOX_IVT_INVM_AREA_R WHERE INVM_AREA_CD_ID IN (
#{item}
) GROUP BY UTLINSTT_ID ) iar ON eim.UTLINSTT_ID = iar.UTLINSTT_ID
WHERE 1=1 AND eim.ACVT_YN = 'Y'
AND tbivcl.UTLINSTT_ID IS NOT NULL AND tbivcl.USE_YN = 'Y'
AND UPPER(eim.ETNM) LIKE '%' || UPPER(#{bplcNm}) || '%'
ORDER BY eim.ENPR_JNNG_DT DESC, eim.INCR_YMD DESC

SELECT *
FROM TB_BOX_IVT_VC_PRTF_L
WHERE UTLINSTT_ID = #{utlinsttId} AND PRTF_ID = #{prtfId}

mapper.insert:
MERGE INTO TB_BOX_IVT_ENPR_INFO_D tbieid
USING DUAL ON (tbieid.UTLINSTT_ID = #{utlinsttId})
WHEN MATCHED THEN
    UPDATE SET
        BSUN_DWAR_CD        = #{bsunDwarCd}
        , EMP_CNT           = #{empCnt}
        , ENPR_INRD_CON     = #{enprInrdCon}
        , AMNN_USER_ID      = #{amnnUserId}
        , AMNN_TS           = CURRENT_TIMESTAMP
WHEN NOT MATCHED THEN
    INSERT
    (
        UTLINSTT_ID
        , BSUN_DWAR_CD
        , EMP_CNT
        , ENPR_INRD_CON
        , CREW_RTRV
        , RGSN_USER_ID
        , RGSN_TS
        , AMNN_USER_ID
        , AMNN_TS
    )
    VALUES
    (
        #{utlinsttId}
        , #{bsunDwarCd}
        , #{empCnt}
        , #{enprInrdCon}
        , 0
        , #{rgsnUserId}
        , CURRENT_TIMESTAMP
        , #{amnnUserId}
        , CURRENT_TIMESTAMP
    )

