mapper.update:
UPDATE
    TB_BOX_IVT_INVM_CNVS_L
SET
    ALRT_CNFA_YN = 'Y'
    , AMNN_USER_ID     = #{amnnUserId}
    , AMNN_TS          = CURRENT_TIMESTAMP
WHERE
    UTLINSTT_ID = #{utlinsttId}
    AND CNVS_RQST_SQN = #{cnvsRqstSqn}
    AND CNVS_RQST_STTS_CD_ID = #{cnvsRqstSttsCdId}

UPDATE
    TB_BOX_IVT_ENPR_INFO_D
SET
    CREW_RTRV = (
        SELECT CASE WHEN CREW_RTRV IS NULL THEN 0 ELSE CREW_RTRV END AS CREW_RTRV
        FROM TB_BOX_IVT_ENPR_INFO_D
        WHERE UTLINSTT_ID = #{utlinsttId}
    ) + 1
WHERE
    UTLINSTT_ID = #{utlinsttId}

UPDATE
    TB_BOX_IVT_VNCM_CPTL_L
SET
    INVM_CMP_PTRN_CD         = #{invmCmpPtrnCd}
    , INVMEXNT_RAP_LMTN_MNCT = #{invmexntRapLmtnMnct}
    , AMNN_USER_ID           = #{amnnUserId}
    , AMNN_TS                = CURRENT_TIMESTAMP
WHERE
    UTLINSTT_ID = #{utlinsttId}

UPDATE
    TB_BOX_IVT_INVM_AMT_R
SET
    INVM_AMT_CD     = #{invmAmtCd}
    , AMNN_USER_ID  = #{amnnUserId}
    , AMNN_TS       = CURRENT_TIMESTAMP
WHERE
    UTLINSTT_ID = #{utlinsttId}

UPDATE
    TB_BOX_IVT_VC_PRTF_L
SET
    INVM_FILD_CD          = #{invmFildCd}
    , UTLZ_TCHN_CD          = #{utlzTchnCd}
    , INVM_ENPR_NM          = #{invmEnprNm}
    , INVM_ENPR_LGTY_IMG_ID = #{fileId}
    , INVM_STG_CD           = #{invmStgCd}
    , INVM_AMT              = #{invmAmt}
    , INVM_PRFR_DT          = #{invmPrfrDt}
    , OPPB_YN               = #{oppbYn}
    , AMNN_USER_ID          = #{amnnUserId}
    , AMNN_TS               = CURRENT_TIMESTAMP
WHERE
    UTLINSTT_ID = #{utlinsttId}
    AND PRTF_ID = #{prtfId}

UPDATE
    TB_BOX_IVT_VC_TMMB_L
SET
    RPRS_CROF_NM        = #{rprsCrofNm}
    , RPRS_CROF_JBCL    = #{rprsCrofJbcl}
    , CRR_CON           = #{crrCon}
    , CROF_IMG_FILE_ID  = #{fileId}

    , AMNN_USER_ID = #{amnnUserId}
    , AMNN_TS      = CURRENT_TIMESTAMP
WHERE
    UTLINSTT_ID = #{utlinsttId}
    AND RPRS_CROF_ID = #{rprsCrofId}

UPDATE
TB_BOX_IVT_ORRP_M
SET
    RPT_DSNC        = #{rptDsnc}
    , FILE_ID    = #{fileId}
    , LADA           = #{lada}
    , AMNN_TS  = CURRENT_TIMESTAMP
    , AMNN_USER_ID = #{rgsnUserId}
WHERE
    INVT_ID = #{invtId}
    AND RPT_DSNC = #{rptDsncPrev}

UPDATE
    TB_BOX_IVT_VC_PAGE_M
SET
    LGTY_IMG_FILE_ID    = #{lgtyImgFileId}
    , HMPG_URL            = #{hmpgUrl}
    , DTL_LKNG_URL_ADR    = #{dtlLkngUrlAdr}
    , RPRS_IMG_FILE_ID    = #{rprsImgFileId}
    , PAGE_TTL            = #{pageTtl}
    , PAGE_CON            = #{pageCon}
    , INRD_IMG_FILE_ID    = #{inrdImgFileId}
    , INRD_TTL            = #{inrdTtl}
    , INRD_CON            = #{inrdCon}
    , FUND_AMT            = #{fundAmt}
    , TTAL_IVEN_CNT       = #{ttalIvenCnt}
    , ETVL_AMT            = #{etvlAmt}
    , INVM_RTRV_ENPR_CNT  = #{invmRtrvEnprCnt}
    , CSCN_TPN            = #{cscnTpn}
    , CSCN_EML_ADR        = #{cscnEmlAdr}
    , CSCN_HMPG_URL       = #{cscnHmpgUrl}
    , CSCN_CPYR_CON       = #{cscnCpyrCon}
    , INVM_APLC_ABYN      = #{invmAplcAbyn}
    , AMNN_USER_ID        = #{amnnUserId}
    , AMNN_TS             = CURRENT_TIMESTAMP
WHERE
    UTLINSTT_ID = #{utlinsttId} AND
    INVM_CMP_EXUS_PAGE_ID = #{invmCmpExusPageId}
